u16 Random(void)
{
    u32 new;
    u32 *pPrev = &gRngPrevValue;
    u32 *pCurrent = &gRngValue;

    u32 prev = *pPrev;
    gRngPrevValue = *pCurrent;

    new = prev + RAND_CONST;
    new += *pCurrent;

    gRngValue = new;

    return ((u16 *)&gRngValue)[1];
}

