void EwramInitHeap(void)
{
    struct EwramNode *root = (struct EwramNode *)&gEwramHeap[0];
    root->next = NULL;
    root->state = sizeof(gEwramHeap);
}

void *EwramMalloc(u32 req)
{
    struct EwramNode *node;
    s32 requestedSpace = req;

    requestedSpace = (req + 3) / 4;
    if (requestedSpace != 0) {
        requestedSpace = requestedSpace * 4 + sizeof(struct EwramNode);
        node = (struct EwramNode *)gEwramHeap;
        while (1) {
            if (requestedSpace <= (u32)node->state) {
                if (requestedSpace == node->state) {
                    node->state = -requestedSpace;
                    return node->space;
                }

                if (requestedSpace + (s32)sizeof(struct EwramNode) <= node->state) {
                    struct EwramNode *addr = (void *)node + requestedSpace;

                    addr->next = node->next;
                    ++node;
                    --node;
                    addr->state = node->state - requestedSpace;
                    node->next = addr;
                    node->state = -requestedSpace;
                    return node->space;
                }
            }
            ++requestedSpace;
            --requestedSpace;
            if (!node->next)
                return ewram_end;
            node = node->next;
        }
    }
    return ewram_end;
}

void EwramFree(void *p)
{
    struct EwramNode *node, *slow, *fast, *tmp;

    if (p && ewram_end != p) {
        node = p - offsetof(struct EwramNode, space);

        for (fast = slow = (struct EwramNode *)gEwramHeap; node != fast; fast = fast->next)
            slow = fast;

        if (node->state < 0)
            node->state = -node->state;

        if ((void *)slow + slow->state == node && slow->state > 0) {
            slow->next = fast->next;
            slow->state += node->state;
            node = slow;
        }

        tmp = (void *)node + node->state;
        if (tmp == node->next && tmp->state > 0) {
            node->state += tmp->state;
            node->next = tmp->next;
        }
    }
}

void numToASCII(u8 digits[5], u16 number)
{
    u8 i;

    for (i = 0; i < 4; number <<= 4, i++) {
        u16 value = ((number & 0xF000) >> 12);
        if (value > 9) {
            digits[i] = value + 87;
        } else {
            digits[i] = value + '0';
        }
    }

    digits[i] = 0;
}

u32 Base10DigitsToHexNibbles(u16 num)
{
    u8 i;
    u16 result;
    u8 lowDigit;
    u16 remainder = num;

    result = 0;
    for (i = 0; i < 4; i++) {
        s32 divisor = Div(remainder, 10);
        lowDigit = remainder - (divisor * 10);
        remainder = divisor;

        result |= lowDigit << (i * 4);
    }

    return result;
}

u32 VerifyFlashSector_Core(u8 *src, u8 *tgt, u32 size)
{
    while (size-- != 0) {
        if (*tgt++ != *src++)
            return (uintptr_t)(tgt - 1);
    }

    return 0;
}

s16 sa2__sub_8004418(s16 x, s16 y)
{
    s16 fraction;
    s32 result;
    u8 index = 0;
    u8 array[8];
    memcpy(array, unkFractions, sizeof(array));

    if ((x | y) == 0) {
        result = -1;
    } else {
        if (x <= 0) {
            x = -x;
            index = 4;
        }
        if (y <= 0) {
            y = -y;
            index += 2;
        }
        if (x >= y) {
            // fraction = y*0.5 / x
            y *= Q(0.5);

            if (x == 0) {
                fraction = y;
            } else {
                fraction = y / x;
            }
        } else {
            index += 1;

            x *= Q(0.5);

            if (y == 0) {
                fraction = x;
            } else {
                fraction = x / y;
            }
        }

        if (array[index] & 0x01) {
            fraction = Q(0.5) - fraction;
        }

        {
            s32 val = array[index] * Q(0.5);
            fraction += val;
            result = ((u32)(fraction << 22) >> 22);
        }
    }

    return result;
}

u32 GetSaveSectorChecksum(SaveSectorData *sector)
{
    u8 *ptr = (u8 *)sector;

    u32 checkSum = 0;
    u32 i = 0;

    u32 size = (sizeof(SaveSectorData) - sizeof(sector->checksum));

    for (; i < size; i += sizeof(u32)) {
        checkSum += *((u32 *)(ptr + i));
    }

    return checkSum;
}

void *VramMalloc(u32 numTiles)
{
    u16 i, j;
    u32 count = numTiles;
    count = (count + (VRAM_TILE_SLOTS_PER_SEGMENT - 1)) / VRAM_TILE_SLOTS_PER_SEGMENT; // round up

    for (i = 0; i < gVramHeapMaxTileSlots / VRAM_TILE_SLOTS_PER_SEGMENT; i++) {
        if (gVramHeapState[i] == 0) {
            for (j = 0; j < count; j++) {
                if (i + j >= (gVramHeapMaxTileSlots / VRAM_TILE_SLOTS_PER_SEGMENT)) {
                    return ewram_end;
                }
                if (gVramHeapState[i + j] != 0) {
                    break;
                }
            }

            if (j == count) {
                gVramHeapState[i] = count;
                return (void *)(gVramHeapStartAddr + i * VRAM_HEAP_SEGMENT_SIZE);
            }
        } else {
            i = (gVramHeapState[i] - 1) + i; // next slot to check, -1 because of ++i
        }
    }
    return ewram_end;
}

u16 VramGetTotalAllocatedTiles(void)
{
    u16 i;
    u16 count = 0;

    for (i = 0; i < gVramHeapMaxTileSlots / VRAM_TILE_SLOTS_PER_SEGMENT; ++i) {
        if (gVramHeapState[i]) {
            count += gVramHeapState[i];
            i = gVramHeapState[i] - 1 + i; // next slot to check, -1 because of ++i
        }
    }
    return count * VRAM_TILE_SLOTS_PER_SEGMENT;
}

void GetInput(void)
{
    s8 i;
    u8 *repeatKeyCounters = gRepeatedKeysTestCounter, *firstIntervals = gKeysFirstRepeatIntervals,
       *continuedHoldIntervals = gKeysContinuedRepeatIntervals;

    gInput = (~REG_KEYINPUT & KEYS_MASK);

    // My guess is that whilst the input recorder
    // is running we still want to know the actual
    // input. For example; to be able to know when
    // to exit the demo
    gPhysicalInput = gInput;

#ifndef COLLECT_RINGS_ROM
    if (gInputRecorder.mode == RECORDER_RECORD) {
        InputRecorderWrite(gInput);
    } else if (gInputRecorder.mode == RECORDER_PLAYBACK) {
        gInput = InputRecorderRead();
    }
#endif

    gPressedKeys = (gInput ^ gPrevInput) & gInput;
    gReleasedKeys = (gInput ^ gPrevInput) & gPrevInput;
    gPrevInput = gInput;

    // Repeated keys will be the currently pressed keys
    gRepeatedKeys = gPressedKeys;

    // Calculate the next repeated state for every key
    for (i = 0; i < 10; i++) {
        if (!GetBit(gInput, i)) {
            // If a key is not pressed, reset its counter
            // to the settings for that key's
            // first repeat interval
            repeatKeyCounters[i] = firstIntervals[i];
        } else if (repeatKeyCounters[i] > 0) {
            // If the key is not yet ready to be repeated
            // continue to wait
            repeatKeyCounters[i]--;
        } else {
            // If the key is ready to be repeated,
            // add the key to the repeated keys
            gRepeatedKeys |= 1 << i;
            // And reset its counter to the settings
            // for continued hold interval
            repeatKeyCounters[i] = continuedHoldIntervals[i];
        }
    }
}

